async function safeFetch(url: string) {
  try {
    const r = await fetch(url)
    if (!r.ok) throw new Error(`HTTP ${r.status}`)
    return await r.json()
  } catch (e) {
    console.error('fetch failed', url, e)
    return null
  }
}
